function.body:
vResult				VARCHAR2(2000);
	vMessage			VARCHAR2(2000);

	cPar				RECORD;
	vRecord				RECORD;
	vRecordID			VARCHAR2(32);
	vClientID			VARCHAR2(32);
	vOrgID				VARCHAR2(32);
	vUserID				VARCHAR2(32);

BEGIN

	DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing '||PInstance_ID) ;
	vResult := 'PInstanceNotFound';
 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'Y', NULL, NULL) ;

	BEGIN

		vResult := 'ReadingParameters';
		FOR cPar IN (
			SELECT i.Record_ID,
				i.AD_User_ID,
				i.AD_Client_ID,
				i.AD_Org_ID,
				pa.ParameterName,
				pa.P_String,
				pa.P_Number,
				pa.P_Date
			FROM AD_PInstance i
				LEFT JOIN AD_PInstance_Para AS pa ON pa.AD_PInstance_ID = i.AD_PInstance_ID
			WHERE i.AD_PInstance_ID = PInstance_ID
		) LOOP
			vRecordID := cPar.Record_ID;
			vClientID := cPar.AD_Client_ID;
			vOrgID := cPar.AD_Org_ID;
			vUserID := cPar.AD_User_ID;
		END LOOP;

		SELECT * INTO vRecord FROM ssimpcn_imp_consolidation WHERE ssimpcn_imp_consolidation_id = vRecordID;
		IF vRecord.processing = 'Y' THEN
			RAISE_APPLICATION_ERROR(-20000, '@DocBeingProcessed@');
		END IF;

		UPDATE ssimpcn_imp_consolidation SET processing = 'Y' WHERE ssimpcn_imp_consolidation_id = vRecordID;

		DELETE FROM ssimpcn_importation_cost WHERE ssimpcn_imp_consolidation_id = vRecordID;
		INSERT INTO ssimpcn_importation_cost (
			ssimpcn_importation_cost_id, ad_client_id, ad_org_id, createdby, updatedby,
    		ssimpcn_imp_consolidation_id, c_bpartner_id, "date", c_doctype_id, documentno,
			referenceno, amountnet, c_invoiceline_id, gl_journalline_id
		)
		SELECT il.c_invoiceline_id, vClientID, vOrgID, vUserID, vUserID,
			il.em_ssimpcn_imp_consol_id, i.c_bpartner_id, i.dateinvoiced, i.c_doctype_id, i.documentno,
			i.POReference, il.LineNetAmt, il.c_invoiceline_id, NULL
		FROM c_invoiceline il
			JOIN c_invoice i ON i.c_invoice_id = il.c_invoice_id
		WHERE il.em_ssimpcn_imp_consol_id = vRecordID
			AND il.em_ssimpcn_type = 'C'
			AND il.EM_Ssimacc_Dataimport = 'N'
			AND i.docstatus = 'CO'

		UNION

		SELECT jl.gl_journalline_id, vClientID, vOrgID, vUserID, vUserID,
			jl.em_ssimpcn_imp_consol_id, NULL, jb.datedoc, j.c_doctype_id, jb.documentno,
			NULL, jl.AmtSourceDr, NULL, jl.gl_journalline_id
		FROM gl_journalline jl
			JOIN gl_journal j ON j.gl_journal_id = jl.gl_journal_id
			JOIN gl_journalbatch jb ON jb.gl_journalbatch_id = j.gl_journalbatch_id
		WHERE jl.em_ssimpcn_imp_consol_id = vRecordID
			AND jl.em_ssimpcn_type = 'C'
			AND j.docstatus = 'CO';

		UPDATE ssimpcn_imp_consolidation SET processing = 'N' WHERE ssimpcn_imp_consolidation_id = vRecordID;
		DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || vMessage) ;
	 AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 1, vMessage);
		RETURN;

	END;

	EXCEPTION WHEN OTHERS THEN
    UPDATE ssimpcn_imp_consolidation SET processing = 'N' WHERE ssimpcn_imp_consolidation_id = vRecordID;
    vResult := '@ERROR='||SQLERRM;
    DBMS_OUTPUT.PUT_LINE( vResult) ;
    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, vResult) ;

    RETURN;
END SSIMPCN_CHARGE_COSTS
